    params[0] = OSSL_PARAM_construct8(OSSL_MAC_PARAM_KEY, (unsigned char *)key, strlen(key));
    params[1] = OSSL_PARAM_construct_utf8_string(OSSL_MAC_PARAM_ALG, "SHA256", 0);

    // 4. Initialize the context with parameters
    if (EVP_MAC_init(ctx, params, 2) <= 0) {
        fprintf(stderr, "Failed to initialize MAC\n");
        EVP_MAC_CTX_free(ctx);
        EVP_MAC_free(mac);
        return 1;
    }

    // 5. Update with the message
